<?php

/**
 * Hand-written code. NOT generated by Speakeasy. Safe from regeneration.
 *
 * @see docs/REGENERATION.md
 */

declare(strict_types=1);

namespace Factuarea\Sdk\Custom\Idempotency;

use Factuarea\Sdk\Hooks\BeforeRequestContext;
use Factuarea\Sdk\Hooks\BeforeRequestHook;
use Psr\Http\Message\RequestInterface;

/**
 * Automatically attaches an `Idempotency-Key` header to every mutating request
 * (POST, PUT, PATCH, DELETE) that does not already carry one.
 *
 * The Factuarea API treats `Idempotency-Key` as a safe-retry token: replaying a
 * request with the same key returns the original result instead of performing
 * the operation twice, and the replayed response carries `Idempotent-Replayed: true`.
 *
 * The SDK's retry layer reuses the SAME request object across retries, so the
 * key generated here is stable for the lifetime of a single logical call: a POST
 * that is transparently retried after a 5xx keeps its key, making the retry
 * idempotent end-to-end.
 *
 * Callers may always override this by passing an explicit `idempotencyKey`
 * argument to a generated operation; in that case the header is already present
 * and this hook leaves it untouched.
 *
 * The generated key is a random UUID v4, which matches the API's accepted key
 * shape (1-64 chars).
 */
final class IdempotencyHook implements BeforeRequestHook
{
    private const HEADER = 'Idempotency-Key';

    private const MUTATING_METHODS = ['POST', 'PUT', 'PATCH', 'DELETE'];

    public function beforeRequest(BeforeRequestContext $context, RequestInterface $request): RequestInterface
    {
        $method = strtoupper($request->getMethod());

        if (! in_array($method, self::MUTATING_METHODS, true)) {
            return $request;
        }

        if ($request->hasHeader(self::HEADER)) {
            return $request;
        }

        return $request->withHeader(self::HEADER, self::uuidV4());
    }

    /**
     * Generate a random RFC 4122 version 4 UUID using a CSPRNG.
     */
    public static function uuidV4(): string
    {
        $bytes = random_bytes(16);
        $bytes[6] = chr((ord($bytes[6]) & 0x0F) | 0x40);
        $bytes[8] = chr((ord($bytes[8]) & 0x3F) | 0x80);

        return vsprintf('%s%s-%s-%s-%s-%s%s%s', str_split(bin2hex($bytes), 4));
    }
}
